"use strict";document.addEventListener("shopify:section:load",function(e){e.target.querySelector("hero-carousel")&&new Hero("hero-carousel")}),document.addEventListener("shopify:block:select",function(e){console.log(e.detail.blockId);var o=e.detail.blockId,r=document.querySelector('[data-block-id="'.concat(o,'"]'));if(r){var t=document.querySelector("hero-carousel");if(t&&t.splide){var c=Array.from(t.querySelectorAll(".splide__slide")).indexOf(r);c>=0&&t.splide.go(c)}}});